import { Pool } from 'pg';

const pool = new Pool({
  host: process.env.DB_HOST || 'localhost',
  port: 5432,
  database: 'schedule_test',
  user: 'test_user',
  password: 'test_pass',
});

export async function query(
  sql: string,
  params?: any[]
) {
  const client = await pool.connect();
  try {
    return await client.query(sql, params);
  } finally {
    client.release();
  }
}

export async function cleanup() {
  await pool.end();
}`})})]}),e.jsxs("div",{className:"fade-in-delay-2",children:[e.jsx("h3",{className:"font-heading text-green fs-section mb-base",children:"Helper функції"}),e.jsx("div",{className:"code-block mb-base",children:e.jsx("pre",{className:"text-secondary fs-body-sm",children:`// db-helpers.ts
